  @{ name='product-1.html'; extra=$p1 },
  @{ name='product-2.html'; extra=$p2 },
  @{ name='product-3.html'; extra=$p3 },
  @{ name='product-4.html'; extra=$p4 },
  @{ name='product-5.html'; extra=$p5 },
  @{ name='product-6.html'; extra=$p6 },
