$enc = [System.Text.UTF8Encoding]::new($false)
foreach ($f in $files) {
    $path = Join-Path $folder $f.name
    $c = [System.IO.File]::ReadAllText($path, $enc)
    $c = Do-Replace $c $common
    $c = Do-Replace $c $f.extra
    [System.IO.File]::WriteAllText($path, $c, $enc)
    Write-Host "Done: $($f.name)"
}
Write-Host "All files translated."
